        # Arrange: create a package.json fixture
        [string]$json = @'
{
    "name": "test-app",
    "dependencies": {
        "express": "^4.18.0",
        "lodash": "~4.17.21",
        "evil-gpl-lib": "1.0.0",
        "mystery-pkg": "2.0.0"
    }
}
'@
