            DenyList  = [string[]]@('GPL-3.0', 'AGPL-3.0')
        }

        # Act
        [PSCustomObject]$report = New-ComplianceReport -ManifestPath $tempFile -LicenseDatabase $mockDb -Config $config

        # Assert: report has summary and entries
